// Dentro de Dashboard.js, actualiza esta función:

const agregarSucursal = (datosCompletos) => {
  const nuevo = { 
    id: Date.now().toString(), 
    ...datosCompletos 
  };
  
  const nuevosLocales = [...locales, nuevo];
  setLocales(nuevosLocales);
  
  // Guardamos en la lista global
  localStorage.setItem('mis-locales', JSON.stringify(nuevosLocales));
  
  // IMPORTANTE: Lo activamos para que DashboardVendedor sepa dónde publicar
  localStorage.setItem('local-actual', JSON.stringify(nuevo));
  
  setShowModal(false);
  alert(`Local "${nuevo.nombre}" creado con éxito en ${nuevo.zona}`);
};
